func payrollEmployeeHistoryEmployeeLabel(employee models.Employee) string {
	name := employee.SearchName()
	if name == "" {
		name = "Employee " + Uitoa(employee.ID)
	}
	if employee.EmployeeNo != "" {
		return name + " (" + employee.EmployeeNo + ")"
	}
	return name
}

